        {'id': 'Microsoft.Extensions.DependencyInjection.Abstractions', 'requestedVersion': '9.0.0', 'resolvedVersion': '9.0.0'}
      ]}]
    }
  ]
}
with open('baseline-packages.json', 'w') as f:
    json.dump(baseline, f, indent=2)

# Compare
after = json.load(open('after-cpm-packages.json'))
def extract(data):
    result = {}
    for p in data['projects']:
        name = p['path'].split('/')[-1]
        for fw in p['frameworks']:
            for pkg in fw.get('topLevelPackages', []):
                result[(name, pkg['id'])] = pkg['resolvedVersion']
    return result

b = extract(baseline)
a = extract(after)
if b == a:
    print('IDENTICAL - conversion is fully version-neutral')
else:
    for k in sorted(set(list(b.keys()) + list(a.keys()))):
        bv = b.get(k, 'MISSING')
        av = a.get(k, 'MISSING')
        if bv != av:
            print(f'CHANGED: {k[0]} {k[1]}: {bv} -> {av}')
